#include<bits/stdc++.h>
using namespace std;
struct node{
	int x,y;
}w[20005];
bool cmp(node x,node y){
	return x.x>y.x;
}
int main(void){
	int n,m,k,a[50005],ans=0;
	cin>>n>>m>>k;
	for(int i=1;i<=k;i++)cin>>a[i];
	for(int i=0;i<n;i++)cin>>w[i].x>>w[i].y;
	sort(w,w+n,cmp);
	for(int i=0;i<n;i++){
		if(a[w[i].y]&&m){
			m--,a[w[i].y]--,ans+=w[i].x;
		}
	}
	cout<<ans;
	return false;
}
